func TestReader_ParameterSyncHookMatchesParsedParameter(t *testing.T) {
	// ID=5, Protocol16 int8 (0x62), value 127
	paramBytes := []byte{5, 0x62, 0x7F}

	r := reader.NewReader(paramBytes)
	h := hooks.NewHooks[v16.Parameter]()
	var got v16.Parameter
	h.SyncHooks.OnParameter = func(p v16.Parameter) { got = p }

	p := &v16.Parameter{}
	out := &v16.Parameter{}
	if err := p.Parse(r, out, h); err != nil {
		t.Fatalf("Parse parameter: %v", err)
	}

	if !reflect.DeepEqual(got, *p) {
		t.Fatalf("sync hook parameter mismatch:\ngot: %+v\nparam: %+v", got, *p)
	}
}

func TestReader_ParameterAsyncHookReceivesMatchingParameter(t *testing.T) {
	paramBytes := []byte{5, 0x62, 0x7F}

	r := reader.NewReader(paramBytes)
	h := hooks.NewHooks[v16.Parameter]()
	_ = h.OnParameterAsync(types.HookOptions{Size: 1})

	p := &v16.Parameter{}
	out := &v16.Parameter{}
	if err := p.Parse(r, out, h); err != nil {
		t.Fatalf("Parse parameter: %v", err)
	}

	select {
	case got := <-h.AsyncHooks.OnParameter:
		if !reflect.DeepEqual(got, *p) {
			t.Fatalf("async parameter mismatch:\ngot: %+v\nparam: %+v", got, *p)
		}
	case <-time.After(time.Second):
		t.Fatal("timeout waiting for async parameter")
	}
}
